input.new_string:
const countNeighbors = (
  x: number,
  y: number,
  aliveCells: Set<string>
): number => {
  let count = 0;
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      if (aliveCells.has(`${x + dx},${y + dy}`)) {
        count++;
      }
    }
  }
  return count;
};

export const advanceGenerations = (
  aliveCells: [number, number][],
  steps: number
): [number, number][] => {
  if (steps === 0) {
    return aliveCells;
  }

  let alive = new Set(aliveCells.map(([x, y]) => `${x},${y}`));

  for (let step = 0; step < steps; step++) {
    const cellsToCheck = new Set<string>();

    // Add all alive cells and their neighbors to check
    for (const cellStr of alive) {
      const [x, y] = cellStr.split(",").map(Number);
      cellsToCheck.add(cellStr);
      for (let dx = -1; dx <= 1; dx++) {
        for (let dy = -1; dy <= 1; dy++) {
          if (dx === 0 && dy === 0) continue;
          cellsToCheck.add(`${x + dx},${y + dy}`);
        }
      }
    }

    const newAlive = new Set<string>();

    for (const cellStr of cellsToCheck) {
      const [x, y] = cellStr.split(",").map(Number);
      const neighbors = countNeighbors(x, y, alive);
      const isAlive = alive.has(cellStr);

      if (isAlive && (neighbors === 2 || neighbors === 3)) {
        newAlive.add(cellStr);
      } else if (!isAlive && neighbors === 3) {
        newAlive.add(cellStr);
      }
    }

    alive = newAlive;
  }

  return Array.from(alive)
    .map(cellStr => cellStr.split(",").map(Number) as [number, number])
    .sort(([x1, y1], [x2, y2]) => x1 !== x2 ? x1 - x2 : y1 - y2);
};

