import { describe, it, expect } from "vitest";
import { advanceGenerations } from "./game-of-life.js";

describe("Game of Life", () => {
  it("should return alive cells unchanged when steps is 0", () => {
    const input = { aliveCells: [[5, 5]], steps: 0 };
    const result = advanceGenerations(input.aliveCells, input.steps);
    expect(result).toEqual([[5, 5]]);
  });
  it("should kill a lone cell with 0 neighbors after 1 generation", () => {
    const result = advanceGenerations([[5, 5]], 1);
    expect(result).toEqual([]);
  });
  it.todo("should keep a cell alive when it has 2 neighbors");
  it.todo("should keep a cell alive when it has 3 neighbors");
  it.todo("should kill a cell when it has more than 3 neighbors");
  it.todo("should create a new cell when a dead cell has exactly 3 neighbors");
  it.todo("should preserve a still life pattern (tub) across a generation");
  it.todo("should advance through multiple generations correctly");
});

